{
  "name": "ThinkStack",
  "description": "A high-leverage personal operating system for builders, consultants, and creators to connect knowledge with execution.",
  "requestFramePermissions": []
}

export type Priority = "Low" | "Medium" | "High";

export type EntityType = "knowledge" | "job" | "client" | "task" | "subscription";

export interface BaseEntity {
  id: string;
  type: EntityType;
  title: string;
  createdAt: string;
  updatedAt: string;
  priority?: Priority;
  notes?: string;
  tags?: string[];
  links?: string[];
  relatedIds?: string[];
}

export interface KnowledgeEntity extends BaseEntity {
  type: "knowledge";
  category: KnowledgeCategory;
  summary: string;
  promptResponse: string;
}

export type JobStatus = "Apply" | "Applied" | "Interview" | "Rejected" | "Offer";

export interface JobEntity extends BaseEntity {
  type: "job";
  company: string;
  role: string;
  jobLink: string;
  status: JobStatus;
  followUpDate?: string;
}

export interface ClientEntity extends BaseEntity {
  type: "client";
  industry: string;
  status: "Active" | "Inactive";
}

export interface TaskEntity extends BaseEntity {
  type: "task";
  clientId?: string;
  dueDate?: string;
  status: "Todo" | "In Progress" | "Done";
}

export interface SubscriptionEntity extends BaseEntity {
  type: "subscription";
  cost: number;
  billingCycle: "Monthly" | "Yearly";
  whyExists: string;
  keep: boolean;
}

export type Entity = KnowledgeEntity | JobEntity | ClientEntity | TaskEntity | SubscriptionEntity;

export type KnowledgeCategory = 
  | 'ai-code' 
  | 'design' 
  | 'media' 
  | 'business' 
  | 'automation' 
  | 'teaching' 
  | 'productivity' 
  | 'people';

export interface CategoryInfo {
  id: KnowledgeCategory;
  label: string;
  icon: string;
  prompt: string;
}

import { CategoryInfo } from './types';

export const KNOWLEDGE_CATEGORIES: CategoryInfo[] = [
  { id: 'ai-code', label: 'AI & Code', icon: '🤖', prompt: 'What problem does this solve?' },
  { id: 'design', label: 'Design Tools', icon: '🎨', prompt: 'How will this improve your workflow?' },
  { id: 'media', label: 'Media Tools', icon: '🎬', prompt: 'What content will you create?' },
  { id: 'business', label: 'Business Ideas', icon: '💰', prompt: 'Who would pay for this?' },
  { id: 'automation', label: 'AI Automations', icon: '⚡', prompt: 'What manual task does this eliminate?' },
  { id: 'teaching', label: 'Teaching Notes', icon: '🎓', prompt: 'How would you explain this to someone else?' },
  { id: 'productivity', label: 'Productivity', icon: '🔧', prompt: 'How will this make you more efficient?' },
  { id: 'people', label: 'Creators & Experts', icon: '👤', prompt: 'Why is this person worth following?' },
];

export const JOB_STATUSES = ['Apply', 'Applied', 'Interview', 'Rejected', 'Offer'] as const;

export const PRIORITY_COLORS: Record<string, string> = {
  High: 'bg-red-50 text-red-700 border-red-100',
  Medium: 'bg-amber-50 text-amber-700 border-amber-100',
  Low: 'bg-slate-50 text-slate-600 border-slate-100',
};

import { Entity } from '../types';

const STORAGE_KEY = 'thinkstack_data';

export const storage = {
  saveEntities: (entities: Entity[]) => {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(entities));
  },

  loadEntities: (): Entity[] => {
    const data = localStorage.getItem(STORAGE_KEY);
    return data ? JSON.parse(data) : [];
  },

  clear: () => {
    localStorage.removeItem(STORAGE_KEY);
  }
};

import { GoogleGenAI } from "@google/genai";
import { Entity } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export async function getDailyRecommendations(entities: Entity[]) {
  const prompt = `
    Analyze this set of personal operating system data for a high-leverage builder.
    Recommend "What to Build Today" based on:
    1. High-priority knowledge/ideas that haven't been acted upon.
    2. Overdue or high-priority client tasks.
    3. Active job opportunities (especially in Interview stage).
    4. Connections between tools/ideas and client needs.

    Data: ${JSON.stringify(entities.slice(0, 50))} // Sending a sample for context

    Return a JSON object with this structure:
    {
      "recommendation": "A concise, high-leverage suggestion (max 20 words)",
      "rationale": "One sentence explaining why this is the focus today",
      "actionItems": ["Task 1", "Task 2"]
    }
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: prompt,
      config: {
        responseMimeType: "application/json",
      },
    });

    return JSON.parse(response.text || "{}");
  } catch (error) {
    console.error("Gemini failed:", error);
    return {
      recommendation: "Focus on your highest priority client task.",
      rationale: "Automated analysis unavailable, defaulting to basic priority logic.",
      actionItems: ["Review High Priority tasks", "Check Knowledge Brain"]
    };
  }
}

