import React from 'react';
import { Entity, Priority } from '../types';
import { PRIORITY_COLORS } from '../constants';

interface EntityCardProps {
  entity: Entity;
  onDelete?: (id: string) => void;
  onClick?: (entity: Entity) => void;
}

export const EntityCard: React.FC<EntityCardProps> = ({ entity, onDelete, onClick }) => {
  const getIcon = () => {
    switch (entity.type) {
      case 'knowledge': return '🧠';
      case 'job': return '💼';
      case 'client': return '👤';
      case 'task': return '✅';
      case 'subscription': return '💳';
      default: return '📄';
    }
  };

  return (
    <div 
      onClick={() => onClick?.(entity)}
      className="group bg-white border border-slate-200 p-5 rounded-2xl hover:border-slate-300 hover:shadow-sm transition-all cursor-pointer relative"
    >
      <div className="flex justify-between items-start mb-3">
        <div className="w-8 h-8 bg-slate-50 rounded-lg flex items-center justify-center text-lg">
          {getIcon()}
        </div>
        {entity.priority && (
          <span className={`text-[10px] font-bold uppercase tracking-wider px-2 py-0.5 rounded border ${PRIORITY_COLORS[entity.priority]}`}>
            {entity.priority}
          </span>
        )}
      </div>

      <h3 className="font-semibold text-slate-900 mb-1 line-clamp-1">{entity.title}</h3>

      {entity.type === 'knowledge' && (
        <p className="text-sm text-slate-500 line-clamp-2 leading-relaxed">
          {entity.summary}
        </p>
      )}

      {entity.type === 'task' && (
        <div className="mt-2 space-y-1">
           <div className="flex items-center text-xs text-slate-500">
            <span className={`w-2 h-2 rounded-full mr-2 ${entity.status === 'Done' ? 'bg-green-400' : 'bg-blue-400'}`}></span>
            {entity.status}
          </div>
          {entity.dueDate && (
            <div className="text-[11px] text-slate-400">Due: {new Date(entity.dueDate).toLocaleDateString()}</div>
          )}
        </div>
      )}

      {entity.type === 'job' && (
        <div className="mt-2 flex items-center space-x-2">
          <span className="text-[10px] bg-slate-100 text-slate-600 px-2 py-0.5 rounded font-medium">
            {entity.company}
          </span>
          <span className="text-[10px] bg-blue-50 text-blue-600 px-2 py-0.5 rounded font-medium">
            {entity.status}
          </span>
        </div>
      )}

      {onDelete && (
        <button 
          onClick={(e) => { e.stopPropagation(); onDelete(entity.id); }}
          className="absolute top-4 right-4 opacity-0 group-hover:opacity-100 text-slate-300 hover:text-red-500 transition-opacity p-1"
        >
          <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" /></svg>
        </button>
      )}
    </div>
  );
};

import React, { useEffect, useState, useMemo } from 'react';
import { Entity, KnowledgeEntity, TaskEntity, JobEntity } from '../types';
import { getDailyRecommendations } from '../services/geminiService';
import { EntityCard } from '../components/EntityCard';

export const Dashboard: React.FC<{ entities: Entity[] }> = ({ entities }) => {
  const [recommendation, setRecommendation] = useState<any>(null);
  const [loading, setLoading] = useState(false);

  useEffect(() => {
    async function fetchRecommendation() {
      if (entities.length === 0) return;
      setLoading(true);
      const res = await getDailyRecommendations(entities);
      setRecommendation(res);
      setLoading(false);
    }
    fetchRecommendation();
  }, [entities.length === 0]);

  const urgentTasks = useMemo(() => 
    entities.filter(e => e.type === 'task' && e.status !== 'Done' && (e.priority === 'High')) as TaskEntity[]
  , [entities]);

  const openLoops = useMemo(() => {
    const jobs = entities.filter(e => e.type === 'job' && e.status === 'Interview') as JobEntity[];
    const highPriorityKnowledge = entities.filter(e => e.type === 'knowledge' && e.priority === 'High').slice(0, 3) as KnowledgeEntity[];
    return [...jobs, ...highPriorityKnowledge];
  }, [entities]);

  return (
    <div className="space-y-10 animate-in fade-in slide-in-from-bottom-2 duration-700">
      <header>
        <h1 className="text-3xl font-bold text-slate-900">Good morning, Builder.</h1>
        <p className="text-slate-500 mt-1">Today is {new Date().toLocaleDateString(undefined, { weekday: 'long', month: 'long', day: 'numeric' })}.</p>
      </header>

      {/* Strategy Section */}
      <section className="bg-white border border-slate-200 rounded-3xl p-8 shadow-sm">
        <div className="flex items-center space-x-2 mb-6">
          <div className="w-8 h-8 bg-blue-600 rounded-lg flex items-center justify-center text-white">
            <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M13 10V3L4 14h7v7l9-11h-7z" /></svg>
          </div>
          <h2 className="text-lg font-bold uppercase tracking-tight text-slate-800">What to Build Today</h2>
        </div>

        {loading ? (
          <div className="animate-pulse space-y-3">
            <div className="h-8 bg-slate-100 rounded-lg w-3/4"></div>
            <div className="h-4 bg-slate-50 rounded-lg w-1/2"></div>
          </div>
        ) : recommendation ? (
          <div className="space-y-4">
            <div className="text-2xl font-semibold text-slate-900 leading-tight">
              {recommendation.recommendation}
            </div>
            <p className="text-slate-500 border-l-2 border-blue-100 pl-4 italic">
              {recommendation.rationale}
            </p>
            <div className="flex flex-wrap gap-2 mt-4">
              {recommendation.actionItems?.map((item: string, i: number) => (
                <div key={i} className="bg-blue-50 text-blue-700 text-xs font-medium px-3 py-1.5 rounded-full flex items-center">
                   <span className="mr-1.5">⚡</span> {item}
                </div>
              ))}
            </div>
          </div>
        ) : (
          <p className="text-slate-400">Capture some ideas or tasks to see daily recommendations.</p>
        )}
      </section>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
        {/* Urgent Tasks */}
        <section>
          <div className="flex items-center justify-between mb-4 px-2">
            <h2 className="text-sm font-bold uppercase tracking-widest text-slate-400">Urgent Execution</h2>
            <span className="text-[10px] bg-red-100 text-red-600 px-2 py-0.5 rounded-full font-bold">{urgentTasks.length}</span>
          </div>
          <div className="space-y-3">
            {urgentTasks.length > 0 ? urgentTasks.map(task => (
              <EntityCard key={task.id} entity={task} />
            )) : (
              <div className="p-12 border-2 border-dashed border-slate-100 rounded-3xl flex flex-col items-center justify-center text-slate-300">
                 <p className="text-sm">Clean slate. Nice work.</p>
              </div>
            )}
          </div>
        </section>

        {/* Open Loops */}
        <section>
          <div className="flex items-center justify-between mb-4 px-2">
            <h2 className="text-sm font-bold uppercase tracking-widest text-slate-400">Open Loops & Leverage</h2>
            <span className="text-[10px] bg-slate-100 text-slate-600 px-2 py-0.5 rounded-full font-bold">{openLoops.length}</span>
          </div>
          <div className="space-y-3">
            {openLoops.length > 0 ? openLoops.map(loop => (
              <EntityCard key={loop.id} entity={loop} />
            )) : (
               <div className="p-12 border-2 border-dashed border-slate-100 rounded-3xl flex flex-col items-center justify-center text-slate-300">
                 <p className="text-sm">No critical loops pending.</p>
              </div>
            )}
          </div>
        </section>
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { Entity, KnowledgeEntity, KnowledgeCategory } from '../types';
import { KNOWLEDGE_CATEGORIES } from '../constants';
import { EntityCard } from '../components/EntityCard';

export const KnowledgeBrain: React.FC<{ entities: Entity[], onAdd: (e: Entity) => void, onDelete: (id: string) => void }> = ({ entities, onAdd, onDelete }) => {
  const [isAdding, setIsAdding] = useState(false);
  const [activeCategory, setActiveCategory] = useState<KnowledgeCategory>('ai-code');
  const [formData, setFormData] = useState({
    title: '',
    summary: '',
    promptResponse: '',
    priority: 'Medium' as any
  });

  const knowledgeItems = entities.filter(e => e.type === 'knowledge') as KnowledgeEntity[];
  const selectedCatInfo = KNOWLEDGE_CATEGORIES.find(c => c.id === activeCategory)!;

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const newEntity: KnowledgeEntity = {
      id: crypto.randomUUID(),
      type: 'knowledge',
      category: activeCategory,
      title: formData.title,
      summary: formData.summary,
      promptResponse: formData.promptResponse,
      priority: formData.priority,
      createdAt: new Date().toISOString(),
      updatedAt: new Date().toISOString()
    };
    onAdd(newEntity);
    setIsAdding(false);
    setFormData({ title: '', summary: '', promptResponse: '', priority: 'Medium' });
  };

  return (
    <div className="space-y-8 animate-in fade-in duration-500">
      <div className="flex justify-between items-center">
        <div>
          <h1 className="text-3xl font-bold text-slate-900">Knowledge Brain</h1>
          <p className="text-slate-500">Structured capture of tools, ideas, and resources.</p>
        </div>
        <button 
          onClick={() => setIsAdding(!isAdding)}
          className="bg-black text-white px-6 py-2.5 rounded-xl font-medium hover:bg-slate-800 transition-all flex items-center"
        >
          {isAdding ? 'Close' : 'Capture Thinking'}
        </button>
      </div>

      {isAdding && (
        <div className="bg-white border border-slate-200 rounded-3xl p-8 shadow-sm">
          <form onSubmit={handleSubmit} className="space-y-6">
            <div className="grid grid-cols-2 md:grid-cols-4 lg:grid-cols-8 gap-2">
              {KNOWLEDGE_CATEGORIES.map(cat => (
                <button
                  key={cat.id}
                  type="button"
                  onClick={() => setActiveCategory(cat.id)}
                  className={`flex flex-col items-center p-3 rounded-xl border transition-all ${
                    activeCategory === cat.id ? 'border-black bg-slate-50' : 'border-slate-100 hover:border-slate-300'
                  }`}
                >
                  <span className="text-xl mb-1">{cat.icon}</span>
                  <span className="text-[10px] font-bold uppercase tracking-tighter text-center leading-none">{cat.label}</span>
                </button>
              ))}
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              <div className="space-y-4">
                <div>
                  <label className="block text-xs font-bold text-slate-400 uppercase tracking-widest mb-2">Title</label>
                  <input 
                    required
                    value={formData.title}
                    onChange={e => setFormData({...formData, title: e.target.value})}
                    placeholder="E.g. Framer Motion Docs"
                    className="w-full bg-slate-50 border-none rounded-xl px-4 py-3 text-sm focus:ring-2 focus:ring-black outline-none transition-all"
                  />
                </div>
                <div>
                  <label className="block text-xs font-bold text-slate-400 uppercase tracking-widest mb-2">Key Idea / Summary</label>
                  <textarea 
                    required
                    value={formData.summary}
                    onChange={e => setFormData({...formData, summary: e.target.value})}
                    rows={3}
                    placeholder="What is the essence of this?"
                    className="w-full bg-slate-50 border-none rounded-xl px-4 py-3 text-sm focus:ring-2 focus:ring-black outline-none transition-all resize-none"
                  />
                </div>
              </div>

              <div className="space-y-4">
                <div className="bg-blue-50 p-4 rounded-2xl border border-blue-100">
                  <label className="block text-[10px] font-bold text-blue-600 uppercase tracking-widest mb-2">ThinkStack Prompt: {selectedCatInfo.prompt}</label>
                  <textarea 
                    required
                    value={formData.promptResponse}
                    onChange={e => setFormData({...formData, promptResponse: e.target.value})}
                    rows={4}
                    placeholder="Connect this information to your leverage..."
                    className="w-full bg-white/50 border-none rounded-xl px-4 py-3 text-sm focus:ring-2 focus:ring-blue-400 outline-none transition-all resize-none"
                  />
                </div>
                <div className="flex items-center space-x-4">
                   <div className="flex-1">
                    <label className="block text-xs font-bold text-slate-400 uppercase tracking-widest mb-2">Priority</label>
                    <select 
                      value={formData.priority}
                      onChange={e => setFormData({...formData, priority: e.target.value as any})}
                      className="w-full bg-slate-50 border-none rounded-xl px-4 py-3 text-sm focus:ring-2 focus:ring-black outline-none"
                    >
                      <option>Low</option>
                      <option>Medium</option>
                      <option>High</option>
                    </select>
                  </div>
                  <div className="pt-6">
                    <button type="submit" className="bg-blue-600 text-white px-8 py-3 rounded-xl font-bold hover:bg-blue-700 transition-all shadow-md shadow-blue-100">
                      Save to Brain
                    </button>
                  </div>
                </div>
              </div>
            </div>
          </form>
        </div>
      )}

      <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
        {knowledgeItems.length > 0 ? (
          knowledgeItems.map(item => (
            <EntityCard key={item.id} entity={item} onDelete={onDelete} />
          ))
        ) : (
          <div className="col-span-full py-20 text-center text-slate-400 border-2 border-dashed border-slate-100 rounded-3xl">
            <p className="text-sm">Knowledge base is empty. Start capturing thinking.</p>
          </div>
        )}
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { Entity, JobEntity, JobStatus } from '../types';
import { JOB_STATUSES } from '../constants';
import { EntityCard } from '../components/EntityCard';

export const JobsPipeline: React.FC<{ entities: Entity[], onAdd: (e: Entity) => void, onDelete: (id: string) => void }> = ({ entities, onAdd, onDelete }) => {
  const [isAdding, setIsAdding] = useState(false);
  const [formData, setFormData] = useState({
    company: '',
    role: '',
    jobLink: '',
    status: 'Apply' as JobStatus,
    priority: 'Medium' as any
  });

  const jobs = entities.filter(e => e.type === 'job') as JobEntity[];

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const newJob: JobEntity = {
      id: crypto.randomUUID(),
      type: 'job',
      title: `${formData.role} at ${formData.company}`,
      company: formData.company,
      role: formData.role,
      jobLink: formData.jobLink,
      status: formData.status,
      priority: formData.priority,
      createdAt: new Date().toISOString(),
      updatedAt: new Date().toISOString()
    };
    onAdd(newJob);
    setIsAdding(false);
    setFormData({ company: '', role: '', jobLink: '', status: 'Apply', priority: 'Medium' });
  };

  return (
    <div className="space-y-8 animate-in fade-in duration-500">
      <div className="flex justify-between items-center">
        <div>
          <h1 className="text-3xl font-bold text-slate-900">Jobs Pipeline</h1>
          <p className="text-slate-500">Track and manage career opportunities.</p>
        </div>
        <button 
          onClick={() => setIsAdding(!isAdding)}
          className="bg-black text-white px-6 py-2.5 rounded-xl font-medium hover:bg-slate-800 transition-all"
        >
          {isAdding ? 'Close' : 'Track New Job'}
        </button>
      </div>

      {isAdding && (
        <form onSubmit={handleSubmit} className="bg-white border border-slate-200 rounded-3xl p-8 shadow-sm space-y-4">
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <input 
              required
              placeholder="Company"
              value={formData.company}
              onChange={e => setFormData({...formData, company: e.target.value})}
              className="bg-slate-50 border-none rounded-xl px-4 py-3 text-sm focus:ring-2 focus:ring-black outline-none"
            />
            <input 
              required
              placeholder="Role"
              value={formData.role}
              onChange={e => setFormData({...formData, role: e.target.value})}
              className="bg-slate-50 border-none rounded-xl px-4 py-3 text-sm focus:ring-2 focus:ring-black outline-none"
            />
            <input 
              placeholder="Link (LinkedIn/Website)"
