import React, { useState, useEffect } from 'react';
import { HashRouter as Router, Routes, Route } from 'react-router-dom';
import { Entity } from './types';
import { storage } from './services/storage';
import { Layout } from './components/Layout';
import { Dashboard } from './pages/Dashboard';
import { KnowledgeBrain } from './pages/KnowledgeBrain';
import { JobsPipeline } from './pages/JobsPipeline';
import { ClientsTasks } from './pages/ClientsTasks';
import { Subscriptions } from './pages/Subscriptions';

const App: React.FC = () => {
  const [entities, setEntities] = useState<Entity[]>([]);

  // Load initial data
  useEffect(() => {
    const data = storage.loadEntities();
    setEntities(data);
  }, []);

  // Persist data on change
  useEffect(() => {
    storage.saveEntities(entities);
  }, [entities]);

  const addEntity = (entity: Entity) => {
    setEntities(prev => [entity, ...prev]);
  };

  const deleteEntity = (id: string) => {
    setEntities(prev => prev.filter(e => e.id !== id));
  };

  const updateEntity = (entity: Entity) => {
    setEntities(prev => prev.map(e => e.id === entity.id ? entity : e));
  };

  return (
    <Router>
      <Layout>
        <Routes>
          <Route path="/" element={<Dashboard entities={entities} />} />
          <Route path="/brain" element={<KnowledgeBrain entities={entities} onAdd={addEntity} onDelete={deleteEntity} />} />
          <Route path="/jobs" element={<JobsPipeline entities={entities} onAdd={addEntity} onDelete={deleteEntity} />} />
          <Route path="/clients" element={<ClientsTasks entities={entities} onAdd={addEntity} onDelete={deleteEntity} />} />
          <Route path="/subscriptions" element={<Subscriptions entities={entities} onAdd={addEntity} onDelete={deleteEntity} />} />
        </Routes>
      </Layout>
    </Router>
  );
};

export default App;

