      <div className="flex justify-between items-start mb-3">
        <div className="w-8 h-8 bg-slate-50 rounded-lg flex items-center justify-center text-lg">
          {getIcon()}
        </div>
        <div className="flex flex-col items-end gap-1">
          {entity.priority && (
            <span className={`text-[10px] font-bold uppercase tracking-wider px-2 py-0.5 rounded border ${PRIORITY_COLORS[entity.priority]}`}>
              {entity.priority}
            </span>
          )}
          {isPeople && person?.platform && (
            <span className="text-[9px] bg-slate-900 text-white px-1.5 py-0.5 rounded font-bold uppercase tracking-tighter">
              {person.platform}
            </span>
          )}
          {isJob && (
             <span className={`text-[9px] px-1.5 py-0.5 rounded font-bold uppercase tracking-tighter ${job?.jobCategory === 'Discovery' ? 'bg-purple-100 text-purple-700' : 'bg-blue-100 text-blue-700'}`}>
              {job?.jobCategory || 'Discovery'}
            </span>
          )}
        </div>
      </div>

      <h3 className="font-semibold text-slate-900 mb-1 line-clamp-1">{entity.title}</h3>

      {isPeople && person?.handleOrChannel && (
        <p className="text-[11px] font-mono text-blue-600 mb-2 truncate">
          {person.handleOrChannel}
