      )}

      {entity.type === 'knowledge' && (
        <p className="text-sm text-slate-500 line-clamp-2 leading-relaxed">
          {entity.summary}
        </p>
      )}

      {isPeople && person?.contentLink && (
        <a 
          href={person.contentLink} 
          target="_blank" 
          rel="noopener noreferrer"
          onClick={(e) => e.stopPropagation()}
          className="mt-3 inline-flex items-center text-[10px] font-bold text-slate-400 hover:text-blue-600 uppercase tracking-widest transition-colors"
        >
          View Source 
          <svg className="w-3 h-3 ml-1" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M10 6H6a2 2 0 00-2 2v10a2 2 0 002 2h10a2 2 0 002-2v-4M14 4h6m0 0v6m0-6L10 14" /></svg>
        </a>
      )}

      {entity.type === 'task' && (
        <div className="mt-2 space-y-1">
           <div className="flex items-center text-xs text-slate-500">
            <span className={`w-2 h-2 rounded-full mr-2 ${entity.status === 'Done' ? 'bg-green-400' : 'bg-blue-400'}`}></span>
            {entity.status}
          </div>
          {entity.dueDate && (
            <div className="text-[11px] text-slate-400">Due: {new Date(entity.dueDate).toLocaleDateString()}</div>
          )}
        </div>
      )}

      {isJob && job && (
        <div className="mt-2 space-y-2">
          <div className="flex items-center space-x-2">
            <span className="text-[10px] bg-slate-100 text-slate-600 px-2 py-0.5 rounded font-medium">
              {job.company}
            </span>
            {job.jobCategory === 'Pipeline' && (
              <span className="text-[10px] bg-blue-50 text-blue-600 px-2 py-0.5 rounded font-medium">
                {job.status}
              </span>
            )}
          </div>
          {job.payRange && (
            <p className="text-[11px] text-green-600 font-bold tracking-tight">💰 {job.payRange}</p>
          )}
          {job.jobLink && (
            <a 
              href={job.jobLink}
              target="_blank"
              rel="noopener noreferrer"
              onClick={(e) => e.stopPropagation()}
              className="text-[10px] text-slate-400 hover:text-blue-500 font-bold uppercase tracking-wider block"
            >
              Open Link →
            </a>
          )}
        </div>
      )}

      {onDelete && (
        <button 
          onClick={(e) => { e.stopPropagation(); onDelete(entity.id); }}
          className="absolute top-4 right-4 opacity-0 group-hover:opacity-100 text-slate-300 hover:text-red-500 transition-opacity p-1"
        >
          <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" /></svg>
        </button>
      )}
    </div>
  );
};

export type Priority = "Low" | "Medium" | "High";

export type EntityType = "knowledge" | "job" | "client" | "task" | "subscription";

export type SocialPlatform = 'YouTube' | 'Twitter/X' | 'Skool' | 'GitHub' | 'Other';

export interface BaseEntity {
  id: string;
  type: EntityType;
  title: string;
  createdAt: string;
  updatedAt: string;
  priority?: Priority;
  notes?: string;
  tags?: string[];
  links?: string[];
  relatedIds?: string[]; // Relationship Mapping
  lastAccessedAt?: string; // For Idea Decay/Resurfacing logic
}

export interface KnowledgeEntity extends BaseEntity {
  type: "knowledge";
  category: KnowledgeCategory;
  summary: string;
  promptResponse: string;
  platform?: SocialPlatform;
  handleOrChannel?: string;
  contentLink?: string;
}

export type JobStatus = "Apply" | "Applied" | "Interview" | "Rejected" | "Offer";
export type JobCategory = "Discovery" | "Pipeline";

export interface JobEntity extends BaseEntity {
  type: "job";
  jobCategory: JobCategory;
  company: string;
  role: string;
  jobLink: string;
  status: JobStatus;
  followUpDate?: string;
  payRange?: string;
  confidenceScore?: number; // 1-5 signal for job quality
}

export interface ClientEntity extends BaseEntity {
  type: "client";
  industry: string;
  status: "Active" | "Inactive";
}

export interface TaskEntity extends BaseEntity {
  type: "task";
  clientId?: string;
  dueDate?: string;
  status: "Todo" | "In Progress" | "Done";
  isFocused?: boolean; // For Deep Work mode
}

export interface SubscriptionEntity extends BaseEntity {
  type: "subscription";
  cost: number;
  billingCycle: "Monthly" | "Yearly";
  whyExists: string;
  keep: boolean;
}

export type Entity = KnowledgeEntity | JobEntity | ClientEntity | TaskEntity | SubscriptionEntity;

export type KnowledgeCategory = 
  | 'ai-code' 
  | 'design' 
  | 'media' 
  | 'business' 
  | 'automation' 
  | 'teaching' 
  | 'productivity' 
  | 'people';

export interface CategoryInfo {
  id: KnowledgeCategory;
  label: string;
  icon: string;
  prompt: string;
}

import { GoogleGenAI } from "@google/genai";
import { Entity } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export async function getDailyRecommendations(entities: Entity[]) {
  const prompt = `
    Analyze this set of personal operating system data for a high-leverage builder.
    Recommend "What to Build Today" based on:
    1. High-priority knowledge/ideas that haven't been acted upon.
    2. Overdue or high-priority client tasks.
    3. Active job opportunities.
    4. Resurfacing "stagnant" knowledge (items with priority High but no recent use).

    Data: ${JSON.stringify(entities.slice(0, 50))}

    Return a JSON object:
    {
      "recommendation": "A concise, high-leverage suggestion",
      "rationale": "One sentence explanation",
      "actionItems": ["Task 1", "Task 2"],
      "focusChecklist": ["Daily Protocol Item 1", "Daily Protocol Item 2"]
    }
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: prompt,
      config: { responseMimeType: "application/json" },
    });
    return JSON.parse(response.text || "{}");
  } catch (error) {
    console.error("Gemini failed:", error);
    return null;
  }
}

export async function scoutJobDetails(url: string) {
  const prompt = `Extract Job Role, Company, and estimated Pay Range from this URL: ${url}. 
  Return JSON: {"role": string, "company": string, "payRange": string, "confidence": number (1-5)}`;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: prompt,
      config: { responseMimeType: "application/json" },
    });
    return JSON.parse(response.text || "{}");
  } catch (e) {
    return null;
  }
}

