import React, { useState } from 'react';
import { Entity, JobEntity, JobStatus, JobCategory } from '../types';
import { JOB_STATUSES } from '../constants';
import { EntityCard } from '../components/EntityCard';
import { scoutJobDetails } from '../services/geminiService';

export const JobsPipeline: React.FC<{ entities: Entity[], onAdd: (e: Entity) => void, onDelete: (id: string) => void }> = ({ entities, onAdd, onDelete }) => {
  const [activeTab, setActiveTab] = useState<JobCategory>('Pipeline');
  const [isAdding, setIsAdding] = useState(false);
  const [isScouting, setIsScouting] = useState(false);
  const [formData, setFormData] = useState({
    company: '',
    role: '',
    jobLink: '',
    status: 'Apply' as JobStatus,
    priority: 'Medium' as any,
    payRange: '',
    confidenceScore: 3
  });

  const jobs = entities.filter(e => e.type === 'job') as JobEntity[];
  const discoveryJobs = jobs.filter(j => j.jobCategory === 'Discovery' || !j.jobCategory);
  const pipelineJobs = jobs.filter(j => j.jobCategory === 'Pipeline');

  const handleScout = async () => {
    if (!formData.jobLink) return;
    setIsScouting(true);
    const details = await scoutJobDetails(formData.jobLink);
    if (details) {
      setFormData(prev => ({
        ...prev,
        role: details.role || prev.role,
        company: details.company || prev.company,
        payRange: details.payRange || prev.payRange,
        confidenceScore: details.confidence || 3
      }));
    }
    setIsScouting(false);
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const newJob: JobEntity = {
      id: crypto.randomUUID(),
      type: 'job',
      jobCategory: activeTab,
      title: `${formData.role} at ${formData.company}`,
      company: formData.company,
      role: formData.role,
      jobLink: formData.jobLink,
      status: formData.status,
      priority: formData.priority,
      payRange: formData.payRange,
      confidenceScore: formData.confidenceScore,
      createdAt: new Date().toISOString(),
      updatedAt: new Date().toISOString()
    };
    onAdd(newJob);
    setIsAdding(false);
    setFormData({ company: '', role: '', jobLink: '', status: 'Apply', priority: 'Medium', payRange: '', confidenceScore: 3 });
  };

  return (
    <div className="space-y-8 animate-in fade-in duration-500">
      <div className="flex justify-between items-center">
        <div>
          <h1 className="text-3xl font-bold text-slate-900">Career Hub</h1>
          <p className="text-slate-500">Hunter-mode job tracking and pipeline management.</p>
        </div>
        <button 
          onClick={() => setIsAdding(!isAdding)}
          className="bg-black text-white px-6 py-2.5 rounded-xl font-medium hover:bg-slate-800 transition-all shadow-sm"
        >
          {isAdding ? 'Close' : activeTab === 'Discovery' ? 'Add Remote Role' : 'Track Application'}
        </button>
      </div>

      <div className="flex space-x-1 bg-slate-100 p-1 rounded-xl w-fit">
        <button 
          onClick={() => {setActiveTab('Discovery'); setIsAdding(false);}}
          className={`px-5 py-2 rounded-lg text-sm font-semibold transition-all ${activeTab === 'Discovery' ? 'bg-white shadow-sm text-slate-900' : 'text-slate-500 hover:text-slate-700'}`}
        >
          Remote Discovery
        </button>
        <button 
          onClick={() => {setActiveTab('Pipeline'); setIsAdding(false);}}
          className={`px-5 py-2 rounded-lg text-sm font-semibold transition-all ${activeTab === 'Pipeline' ? 'bg-white shadow-sm text-slate-900' : 'text-slate-500 hover:text-slate-700'}`}
        >
          Application Pipeline
        </button>
      </div>

      {isAdding && (
        <form onSubmit={handleSubmit} className="bg-white border border-slate-200 rounded-3xl p-8 shadow-sm space-y-4 border-t-4 border-t-blue-500">
          <div className="flex space-x-2">
            <input 
              required
              placeholder="Paste Job Link to Scout..."
              value={formData.jobLink}
              onChange={e => setFormData({...formData, jobLink: e.target.value})}
              className="flex-1 bg-slate-50 border-none rounded-xl px-4 py-3 text-sm focus:ring-2 focus:ring-black outline-none"
            />
            <button 
              type="button"
              onClick={handleScout}
              disabled={isScouting}
              className="bg-slate-100 text-slate-600 px-4 py-3 rounded-xl text-xs font-bold hover:bg-slate-200 transition-all disabled:opacity-50"
            >
              {isScouting ? 'Scouting...' : 'AI SCOUT'}
            </button>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <input 
              required
              placeholder="Company"
              value={formData.company}
              onChange={e => setFormData({...formData, company: e.target.value})}
              className="bg-slate-50 border-none rounded-xl px-4 py-3 text-sm focus:ring-2 focus:ring-black outline-none"
            />
            <input 
              required
              placeholder="Role"
              value={formData.role}
              onChange={e => setFormData({...formData, role: e.target.value})}
              className="bg-slate-50 border-none rounded-xl px-4 py-3 text-sm focus:ring-2 focus:ring-black outline-none"
            />
            <div className="flex gap-2">
              {activeTab === 'Pipeline' && (
                <select 
                  value={formData.status}
                  onChange={e => setFormData({...formData, status: e.target.value as JobStatus})}
                  className="flex-1 bg-slate-50 border-none rounded-xl px-4 py-3 text-sm focus:ring-2 focus:ring-black outline-none"
                >
                  {JOB_STATUSES.map(s => <option key={s} value={s}>{s}</option>)}
