          <button type="submit" className="bg-blue-600 text-white w-full py-3 rounded-xl font-bold hover:bg-blue-700 transition-all shadow-md shadow-blue-100">
            {activeTab === 'Discovery' ? 'Add to Discovery' : 'Initialize Application'}
