    onAdd(newTask);
    setIsAdding(false);
    setTaskForm({ title: '', clientId: '', priority: 'Medium', dueDate: '', relatedIds: [] });
  };

  return (
    <div className="space-y-8 animate-in fade-in duration-500">
      <div className="flex justify-between items-center">
        <div>
          <h1 className="text-3xl font-bold text-slate-900">Execution</h1>
          <p className="text-slate-500">Connecting clients, tasks, and relevant tools.</p>
        </div>
        <button 
          onClick={() => setIsAdding(!isAdding)}
          className="bg-black text-white px-6 py-2.5 rounded-xl font-medium"
        >
          {isAdding ? 'Close' : activeTab === 'tasks' ? 'Add Task' : 'Add Client'}
        </button>
      </div>

      <div className="flex space-x-1 bg-slate-100 p-1 rounded-xl w-fit">
        <button onClick={() => setActiveTab('tasks')} className={`px-4 py-1.5 rounded-lg text-sm font-medium transition-all ${activeTab === 'tasks' ? 'bg-white shadow-sm' : ''}`}>Tasks</button>
        <button onClick={() => setActiveTab('clients')} className={`px-4 py-1.5 rounded-lg text-sm font-medium transition-all ${activeTab === 'clients' ? 'bg-white shadow-sm' : ''}`}>Clients</button>
      </div>

      {isAdding && (
        <div className="bg-white border border-slate-200 rounded-3xl p-8 shadow-sm">
          {activeTab === 'tasks' && (
            <form onSubmit={handleAddTask} className="space-y-6">
              <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                <input required placeholder="Task Title" className="bg-slate-50 border-none rounded-xl px-4 py-3 text-sm focus:ring-2 focus:ring-black outline-none" value={taskForm.title} onChange={e => setTaskForm({...taskForm, title: e.target.value})} />
                <select className="bg-slate-50 border-none rounded-xl px-4 py-3 text-sm focus:ring-2 focus:ring-black outline-none" value={taskForm.clientId} onChange={e => setTaskForm({...taskForm, clientId: e.target.value})}>
                  <option value="">No Client Linked</option>
                  {clients.map(c => <option key={c.id} value={c.id}>{c.title}</option>)}
                </select>
              </div>
              <div>
                <label className="block text-[10px] font-bold text-slate-400 uppercase tracking-widest mb-2">Map Relevant Knowledge/Tools</label>
                <div className="flex flex-wrap gap-2 max-h-32 overflow-y-auto p-2 bg-slate-50 rounded-xl">
                  {knowledge.map(k => (
                    <button
                      key={k.id}
                      type="button"
                      onClick={() => {
                        const ids = taskForm.relatedIds.includes(k.id) 
                          ? taskForm.relatedIds.filter(id => id !== k.id)
                          : [...taskForm.relatedIds, k.id];
                        setTaskForm({...taskForm, relatedIds: ids});
                      }}
                      className={`px-3 py-1 rounded-full text-[10px] font-bold transition-all border ${
                        taskForm.relatedIds.includes(k.id) ? 'bg-blue-600 text-white border-blue-600' : 'bg-white text-slate-500 border-slate-200'
                      }`}
                    >
