import React from 'react';
import { Entity, KnowledgeEntity, JobEntity, TaskEntity } from '../types';
import { PRIORITY_COLORS } from '../constants';

interface EntityCardProps {
  entity: Entity;
  onDelete?: (id: string) => void;
  onClick?: (entity: Entity) => void;
}

export const EntityCard: React.FC<EntityCardProps> = ({ entity, onDelete, onClick }) => {
  const getIcon = () => {
    switch (entity.type) {
      case 'knowledge': 
        if ((entity as KnowledgeEntity).category === 'people') return '👤';
        return '🧠';
      case 'job': return '💼';
      case 'client': return '🤝';
      case 'task': return '⚡';
      case 'subscription': return '💳';
      default: return '📄';
    }
  };

  const isPeople = entity.type === 'knowledge' && (entity as KnowledgeEntity).category === 'people';
  const person = isPeople ? (entity as KnowledgeEntity) : null;
  const isJob = entity.type === 'job';
  const job = isJob ? (entity as JobEntity) : null;
  const isTask = entity.type === 'task';
  const task = isTask ? (entity as TaskEntity) : null;

  const getDeadlineInfo = () => {
    if (!job?.deadlineDate) return null;
    const today = new Date();
    const deadline = new Date(job.deadlineDate);
    const diffTime = deadline.getTime() - today.getTime();
    const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24));

    let color = 'text-slate-400';
    if (diffDays <= 3) color = 'text-red-500 font-bold';
    else if (diffDays <= 10) color = 'text-amber-500 font-bold';

    return { diffDays, color };
  };

  const deadline = getDeadlineInfo();

  return (
    <div 
      onClick={() => onClick?.(entity)}
      className="group bg-white border border-slate-200 p-5 rounded-2xl hover:border-slate-300 hover:shadow-md transition-all cursor-pointer relative"
    >
      <div className="flex justify-between items-start mb-3">
        <div className="w-8 h-8 bg-slate-50 rounded-lg flex items-center justify-center text-lg shadow-inner">
          {getIcon()}
        </div>
        <div className="flex flex-col items-end gap-1">
          {entity.priority && (
            <span className={`text-[9px] font-bold uppercase tracking-wider px-2 py-0.5 rounded border ${PRIORITY_COLORS[entity.priority]}`}>
              {entity.priority}
            </span>
          )}
          {isJob && job?.confidenceScore && (
             <div className="flex gap-0.5">
               {[...Array(5)].map((_, i) => (
                 <div key={i} className={`w-1.5 h-1.5 rounded-full ${i < job.confidenceScore! ? 'bg-green-500' : 'bg-slate-200'}`}></div>
               ))}
             </div>
          )}
        </div>
      </div>

      <h3 className="font-semibold text-slate-900 mb-1 line-clamp-1 text-sm tracking-tight">{entity.title}</h3>

      {isPeople && person?.handleOrChannel && (
        <p className="text-[10px] font-mono text-blue-600 mb-2 truncate bg-blue-50 px-2 py-0.5 rounded w-fit">
          {person.handleOrChannel}
        </p>
      )}

      {(entity.type === 'knowledge' || entity.type === 'client') && (
        <p className="text-xs text-slate-500 line-clamp-2 leading-relaxed">
          {entity.notes || (entity as any).summary || (entity as any).industry}
        </p>
      )}

      {isTask && task && (
        <div className="mt-2 space-y-1">
           <div className="flex items-center text-[10px] font-bold uppercase tracking-tighter text-slate-500">
            <span className={`w-2 h-2 rounded-full mr-2 ${task.status === 'Done' ? 'bg-green-500' : 'bg-blue-500'}`}></span>
            {task.status}
          </div>
          <button className="text-[9px] text-blue-600 font-bold bg-blue-50 px-2 py-1 rounded hover:bg-blue-100 transition-colors uppercase tracking-widest">
            Enter Deep Work
          </button>
        </div>
      )}

      {isJob && job && (
        <div className="mt-2 space-y-2">
          <div className="flex items-center justify-between">
            <span className="text-[9px] bg-slate-100 text-slate-600 px-2 py-0.5 rounded font-bold uppercase tracking-tight">
              {job.company}
            </span>
            {deadline && (
              <span className={`text-[9px] uppercase tracking-tighter ${deadline.color}`}>
                {deadline.diffDays < 0 ? 'Expired' : `${deadline.diffDays}d left`}
              </span>
            )}
          </div>
          {job.payRange && (
            <p className="text-[10px] text-green-700 font-bold tracking-tight bg-green-50 px-2 py-0.5 rounded w-fit">💰 {job.payRange}</p>
          )}
        </div>
      )}

      {onDelete && (
        <button 
          onClick={(e) => { e.stopPropagation(); onDelete(entity.id); }}
          className="absolute top-4 right-4 opacity-0 group-hover:opacity-100 text-slate-300 hover:text-red-500 transition-opacity p-1"
        >
          <svg className="w-3 h-3" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" /></svg>
        </button>
      )}
    </div>
  );
};

export type Priority = "Low" | "Medium" | "High";

export type EntityType = "knowledge" | "job" | "client" | "task" | "subscription";

export type SocialPlatform = 'YouTube' | 'Twitter/X' | 'Skool' | 'GitHub' | 'Other';

export interface BaseEntity {
  id: string;
  type: EntityType;
  title: string;
  createdAt: string;
  updatedAt: string;
  priority?: Priority;
  notes?: string;
  tags?: string[];
  links?: string[];
  relatedIds?: string[];
  lastAccessedAt?: string;
}

export interface KnowledgeEntity extends BaseEntity {
  type: "knowledge";
  category: KnowledgeCategory;
  summary: string;
  promptResponse: string;
  platform?: SocialPlatform;
  handleOrChannel?: string;
  contentLink?: string;
}

export type JobStatus = "Apply" | "Applied" | "Interview" | "Rejected" | "Offer" | "Active-Gig";
export type JobCategory = "Discovery" | "Pipeline";
export type GigPlatformStatus = "Scouting" | "Assessing" | "Waitlisted" | "Active";

export interface JobEntity extends BaseEntity {
  type: "job";
  jobCategory: JobCategory;
  company: string; // Platform Name for gigs
  role: string;
  jobLink: string;
  status: JobStatus;
  platformStatus?: GigPlatformStatus;
  followUpDate?: string;
  deadlineDate?: string;
  payRange?: string;
  hourlyRate?: number; // Gig specific
  confidenceScore?: number;
  aiScoutTags?: string[]; // Gemini extracted keywords
}

export interface ClientEntity extends BaseEntity {
  type: "client";
  industry: string;
  status: "Active" | "Inactive";
}

export interface TaskEntity extends BaseEntity {
  type: "task";
  clientId?: string;
  dueDate?: string;
  status: "Todo" | "In Progress" | "Done";
  isFocused?: boolean;
}

export interface SubscriptionEntity extends BaseEntity {
  type: "subscription";
  cost: number;
  billingCycle: "Monthly" | "Yearly";
  whyExists: string;
  keep: boolean;
}

export type Entity = KnowledgeEntity | JobEntity | ClientEntity | TaskEntity | SubscriptionEntity;

export type KnowledgeCategory = 
  | 'ai-code' 
  | 'design' 
  | 'media' 
  | 'business' 
  | 'automation' 
  | 'teaching' 
  | 'productivity' 
  | 'people';

export interface CategoryInfo {
  id: KnowledgeCategory;
  label: string;
  icon: string;
  prompt: string;
}

import { GoogleGenAI } from "@google/genai";
import { Entity } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export async function getDailyRecommendations(entities: Entity[]) {
  const prompt = `
    Analyze this set of personal operating system data for a high-leverage builder.
    Recommend "What to Build Today" based on:
    1. High-priority knowledge/ideas that haven't been acted upon.
    2. Overdue or high-priority client tasks.
    3. Active gig opportunities (Discovery jobs marked as High priority).
    4. Resurfacing "stagnant" knowledge.

    Data: ${JSON.stringify(entities.slice(0, 50))}

    Return a JSON object:
    {
      "recommendation": "A concise, high-leverage suggestion",
      "rationale": "One sentence explanation",
      "actionItems": ["Task 1", "Task 2"],
      "focusChecklist": ["Daily Protocol Item 1", "Daily Protocol Item 2"]
    }
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: prompt,
      config: { responseMimeType: "application/json" },
    });
    return JSON.parse(response.text || "{}");
  } catch (error) {
    console.error("Gemini failed:", error);
    return null;
  }
}

export async function scoutJobDetails(url: string) {
  const prompt = `Extract Job Role, Company/Platform, estimated Pay Range, and required skills (tags) from this URL: ${url}. 
  If it is an AI training gig, note specifically if it is coding or writing.
  Return JSON: {"role": string, "company": string, "payRange": string, "confidence": number (1-5), "tags": string[]}`;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: prompt,
      config: { responseMimeType: "application/json" },
    });
    return JSON.parse(response.text || "{}");
  } catch (e) {
    return null;
  }
}

import React, { useEffect, useState, useMemo } from 'react';
import { Entity, KnowledgeEntity, TaskEntity, JobEntity } from '../types';
import { getDailyRecommendations } from '../services/geminiService';
import { EntityCard } from '../components/EntityCard';

export const Dashboard: React.FC<{ entities: Entity[] }> = ({ entities }) => {
  const [recommendation, setRecommendation] = useState<any>(null);
  const [loading, setLoading] = useState(false);

  useEffect(() => {
    async function fetchRecommendation() {
      if (entities.length === 0) return;
      setLoading(true);
      const res = await getDailyRecommendations(entities);
      setRecommendation(res);
      setLoading(false);
    }
    fetchRecommendation();
  }, [entities.length === 0]);

  const activeGigs = useMemo(() => 
    entities.filter(e => e.type === 'job' && (e as JobEntity).platformStatus === 'Active') as JobEntity[]
  , [entities]);

  const urgentTasks = useMemo(() => 
    entities.filter(e => e.type === 'task' && e.status !== 'Done' && (e.priority === 'High')) as TaskEntity[]
  , [entities]);

  const urgentJobs = useMemo(() => {
    const today = new Date();
    return entities.filter(e => {
      if (e.type !== 'job' || (e as JobEntity).status !== 'Apply' || !(e as JobEntity).deadlineDate) return false;
      const deadline = new Date((e as JobEntity).deadlineDate!);
      const diffTime = deadline.getTime() - today.getTime();
      const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24));
      return diffDays >= 0 && diffDays <= 10;
    }) as JobEntity[];
  }, [entities]);

  const dailyChecklist = useMemo(() => {
    const list = [...(recommendation?.focusChecklist || ['Scout 3 Remote Roles', 'Execute 2 High Priority Tasks', 'Capture 1 New Insight'])];
    urgentJobs.forEach(job => {
      const deadline = new Date(job.deadlineDate!);
      const diffDays = Math.ceil((deadline.getTime() - new Date().getTime()) / (1000 * 60 * 60 * 24));
      list.unshift(`🚨 DEADLINE: ${job.role} (${diffDays} days)`);
    });
    return list;
  }, [recommendation, urgentJobs]);

  return (
    <div className="space-y-10 animate-in fade-in slide-in-from-bottom-2 duration-700">
      <header className="flex justify-between items-end">
        <div>
          <h1 className="text-3xl font-bold text-slate-900 tracking-tight">Command Center</h1>
          <p className="text-slate-500 mt-1">Today is {new Date().toLocaleDateString(undefined, { weekday: 'long', month: 'long', day: 'numeric' })}.</p>
        </div>
        <div className="flex items-center space-x-6">
          <div className="text-right">
            <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Active Income Streams</p>
            <p className="text-lg font-bold text-green-600">{activeGigs.length} Gigs</p>
          </div>
          <div className="w-px h-8 bg-slate-200"></div>
          <div className="hidden md:flex -space-x-2">
             <div className="w-8 h-8 rounded-full bg-blue-100 border-2 border-white flex items-center justify-center text-[10px] font-bold">KB</div>
             <div className="w-8 h-8 rounded-full bg-green-100 border-2 border-white flex items-center justify-center text-[10px] font-bold">$$</div>
             <div className="w-8 h-8 rounded-full bg-slate-100 border-2 border-white flex items-center justify-center text-[10px] font-bold">+</div>
          </div>
        </div>
      </header>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        <section className="lg:col-span-2 bg-white border border-slate-200 rounded-3xl p-8 shadow-sm">
          <div className="flex items-center space-x-2 mb-6">
            <div className="w-8 h-8 bg-blue-600 rounded-lg flex items-center justify-center text-white">
              <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M13 10V3L4 14h7v7l9-11h-7z" /></svg>
            </div>
            <h2 className="text-sm font-bold uppercase tracking-widest text-slate-800">What to Build Today</h2>
          </div>

          {loading ? (
            <div className="animate-pulse space-y-3">
              <div className="h-8 bg-slate-100 rounded-lg w-3/4"></div>
              <div className="h-4 bg-slate-50 rounded-lg w-1/2"></div>
            </div>
          ) : recommendation ? (
            <div className="space-y-4">
              <div className="text-2xl font-semibold text-slate-900 leading-tight">
                {recommendation.recommendation}
              </div>
              <p className="text-slate-500 border-l-2 border-blue-100 pl-4 italic text-sm">
                {recommendation.rationale}
              </p>
              <div className="flex flex-wrap gap-2 mt-4">
                {recommendation.actionItems?.map((item: string, i: number) => (
                  <div key={i} className="bg-blue-50 text-blue-700 text-[10px] font-bold uppercase px-3 py-1.5 rounded-full flex items-center border border-blue-100">
                    <span className="mr-1.5 opacity-50">⚡</span> {item}
                  </div>
                ))}
              </div>
            </div>
          ) : (
            <p className="text-slate-400">Add high-leverage data to see daily strategy.</p>
          )}
        </section>

        <section className="bg-slate-900 text-white rounded-3xl p-8 shadow-xl">
          <h2 className="text-xs font-bold uppercase tracking-widest text-slate-400 mb-6 flex items-center">
            <span className="w-2 h-2 bg-green-500 rounded-full mr-2"></span>
            Daily Protocol
          </h2>
          <ul className="space-y-4">
            {dailyChecklist.map((item: string, i: number) => (
              <li key={i} className="flex items-start group cursor-pointer">
                <div className={`w-5 h-5 rounded border mt-0.5 mr-3 flex-shrink-0 transition-colors ${item.includes('🚨') ? 'border-red-500 bg-red-500/10' : 'border-slate-700 group-hover:border-blue-500'}`}></div>
