        <section>
          <div className="flex items-center justify-between mb-4 px-2">
            <h2 className="text-xs font-bold uppercase tracking-widest text-slate-400">Resurfacing Knowledge</h2>
          </div>
          <div className="p-12 border-2 border-dashed border-slate-100 rounded-3xl text-center text-slate-300 text-sm">
            Knowledge base items will resurface here based on leverage.
          </div>
        </section>
      </div>
    </div>
  );
};

