            <div className="col-span-full py-20 text-center text-slate-300 border-2 border-dashed border-slate-100 rounded-3xl">
              <p className="text-sm">Client roster is empty. Network to build leverage.</p>
            </div>
          )
        )}
      </div>
    </div>
  );
};

export type Priority = "Low" | "Medium" | "High";

export type EntityType = "knowledge" | "job" | "client" | "task" | "subscription";

export type SocialPlatform = 'YouTube' | 'Twitter/X' | 'Skool' | 'GitHub' | 'Other';

export interface BaseEntity {
  id: string;
  type: EntityType;
  title: string;
  createdAt: string;
  updatedAt: string;
  priority?: Priority;
  notes?: string;
  tags?: string[];
  links?: string[];
  relatedIds?: string[];
  lastAccessedAt?: string;
}

export interface KnowledgeEntity extends BaseEntity {
  type: "knowledge";
  category: KnowledgeCategory;
  summary: string;
  promptResponse: string;
  platform?: SocialPlatform;
  handleOrChannel?: string;
  contentLink?: string;
}

export type JobStatus = "Apply" | "Applied" | "Interview" | "Rejected" | "Offer" | "Active-Gig";
export type JobCategory = "Discovery" | "Pipeline";
export type GigPlatformStatus = "Scouting" | "Assessing" | "Waitlisted" | "Active";

export interface JobEntity extends BaseEntity {
  type: "job";
  jobCategory: JobCategory;
  company: string;
  role: string;
  jobLink: string;
  status: JobStatus;
  platformStatus?: GigPlatformStatus;
  followUpDate?: string;
  deadlineDate?: string;
  payRange?: string;
  hourlyRate?: number;
  confidenceScore?: number;
  aiScoutTags?: string[];
}

export interface ClientEntity extends BaseEntity {
  type: "client";
  industry: string;
  status: "Active" | "Inactive";
}

export interface TaskEntity extends BaseEntity {
  type: "task";
  clientId?: string;
  dueDate?: string;
  status: "Todo" | "In Progress" | "Done";
  isFocused?: boolean;
  timeSpentMinutes?: number; // Tracking velocity
}

export interface SubscriptionEntity extends BaseEntity {
  type: "subscription";
  cost: number;
  billingCycle: "Monthly" | "Yearly";
  whyExists: string;
  keep: boolean;
  usageScore?: number; // 1-10 based on how often it's linked to tasks
}

export type Entity = KnowledgeEntity | JobEntity | ClientEntity | TaskEntity | SubscriptionEntity;

export type KnowledgeCategory = 
  | 'ai-code' 
  | 'design' 
  | 'media' 
  | 'business' 
  | 'automation' 
  | 'teaching' 
  | 'productivity' 
  | 'people';

export interface CategoryInfo {
  id: KnowledgeCategory;
  label: string;
  icon: string;
  prompt: string;
}

import React, { useEffect, useState, useMemo } from 'react';
import { Entity, KnowledgeEntity, TaskEntity, JobEntity, SubscriptionEntity } from '../types';
import { getDailyRecommendations } from '../services/geminiService';
import { EntityCard } from '../components/EntityCard';

export const Dashboard: React.FC<{ entities: Entity[] }> = ({ entities }) => {
  const [recommendation, setRecommendation] = useState<any>(null);
  const [loading, setLoading] = useState(false);

  useEffect(() => {
    async function fetchRecommendation() {
      if (entities.length === 0) return;
      setLoading(true);
      const res = await getDailyRecommendations(entities);
      setRecommendation(res);
      setLoading(false);
    }
    fetchRecommendation();
  }, [entities.length === 0]);

  const stats = useMemo(() => {
    const subs = entities.filter(e => e.type === 'subscription') as SubscriptionEntity[];
    const tasks = entities.filter(e => e.type === 'task') as TaskEntity[];
    const monthlyBurn = subs.reduce((acc, s) => acc + (s.billingCycle === 'Monthly' ? s.cost : s.cost / 12), 0);
    const activeGigs = entities.filter(e => e.type === 'job' && (e as JobEntity).platformStatus === 'Active') as JobEntity[];

    // Leverage Score Calculation (Ratio of high priority output to burn)
    const highPriorityTasks = tasks.filter(t => t.priority === 'High' && t.status === 'Done').length;
    const leverageScore = Math.min(100, (highPriorityTasks * 10) + (activeGigs.length * 15));

    return { monthlyBurn, activeGigs, leverageScore };
  }, [entities]);

  const urgentTasks = useMemo(() => 
    entities.filter(e => e.type === 'task' && e.status !== 'Done' && (e.priority === 'High')) as TaskEntity[]
  , [entities]);

  const dailyChecklist = useMemo(() => {
    return [...(recommendation?.focusChecklist || ['Sync high-leverage tools', 'Audit 1 Subscription', 'Update Pipeline Status'])];
  }, [recommendation]);

  return (
    <div className="space-y-10 animate-in fade-in slide-in-from-bottom-2 duration-700 pb-20">
