  const [isAuthenticated, setIsAuthenticated] = useState<boolean | null>(null);

  // Check auth status on mount
  useEffect(() => {
    const checkAuth = async () => {
      const hasKey = await window.aistudio.hasSelectedApiKey();
      setIsAuthenticated(hasKey);
    };
    checkAuth();
  }, []);

  // Load initial data
  useEffect(() => {
    const data = storage.loadEntities();
    setEntities(data);
  }, []);

  // Persist data on change
  useEffect(() => {
    storage.saveEntities(entities);
  }, [entities]);

  const addEntity = (entity: Entity) => {
    setEntities(prev => [entity, ...prev]);
  };

  const deleteEntity = (id: string) => {
    setEntities(prev => prev.filter(e => e.id !== id));
  };

  const updateEntity = (entity: Entity) => {
    setEntities(prev => prev.map(e => e.id === entity.id ? entity : e));
  };

  if (isAuthenticated === null) {
    return <div className="min-h-screen bg-slate-50 flex items-center justify-center font-mono text-xs text-slate-400 animate-pulse">Initializing OS...</div>;
  }

  if (!isAuthenticated) {
    return <AuthGate onAuthenticated={() => setIsAuthenticated(true)} />;
  }

  return (
    <Router>
      <Layout>
        <Routes>
          <Route path="/" element={<Dashboard entities={entities} />} />
          <Route path="/brain" element={<KnowledgeBrain entities={entities} onAdd={addEntity} onDelete={deleteEntity} />} />
