/**
 * ThinkStack Session Storage
 * Transitioned from Local-First to Session-Driven.
 * Data now lives in the application state and is managed per-session.
 */

let sessionCache: Entity[] = [];

export const storage = {
  // We no longer persist to localStorage to remove the "Local-First" footprint
  saveEntities: (entities: Entity[]) => {
    sessionCache = [...entities];
    // console.debug('Session state updated:', sessionCache.length, 'items');
  },

  loadEntities: (): Entity[] => {
    // Returns the current session cache. 
    // In a full production cloud environment, this would fetch from a database.
    return sessionCache;
  },

  clear: () => {
    sessionCache = [];
  }
};

