const App: React.FC = () => {
  const [entities, setEntities] = useState<Entity[]>([]);
  const [isAuthenticated, setIsAuthenticated] = useState<boolean | null>(null);

  // CRITICAL: Refs to track internal state without causing re-renders
  const isLoggingOut = useRef(false);
  const hasLoadedFromStorage = useRef(false);

  useEffect(() => {
    const checkAuth = async () => {
      const hasKey = await window.aistudio.hasSelectedApiKey();
      setIsAuthenticated(hasKey);
    };
    checkAuth();
  }, []);

  // LOAD LOGIC: Only run once when authentication status is confirmed
  useEffect(() => {
    if (isAuthenticated === true) {
      console.log("Auth confirmed, checking vault...");
      const data = storage.loadEntities();
      if (data && data.length > 0) {
        console.log(`Vault found with ${data.length} items. Mounting to OS...`);
        setEntities(data);
      } else {
        console.log("Vault is empty or new session.");
      }
      // CRITICAL: We mark as loaded REGARDLESS of whether data was found or not
      // This allows the Save effect (below) to start tracking changes
      hasLoadedFromStorage.current = true;
      isLoggingOut.current = false;
    }
  }, [isAuthenticated]);

  // SYNC LOGIC: Only save if we have successfully completed the load process
  useEffect(() => {
    if (isAuthenticated && !isLoggingOut.current && hasLoadedFromStorage.current) {
      // We only save if the load process is complete. 
      // This prevents the initial [] state from overwriting a full database.
      storage.saveEntities(entities);
    }
  }, [entities, isAuthenticated]);

  const addEntity = (entity: Entity) => {
    setEntities(prev => [entity, ...prev]);
  };

  const deleteEntity = (id: string) => {
    setEntities(prev => prev.filter(e => e.id !== id));
  };

  const updateEntity = (entity: Entity) => {
    setEntities(prev => prev.map(e => 
      e.id === entity.id 
        ? { ...entity, updatedAt: new Date().toISOString() } 
        : e
    ));
  };

  const handleLogout = () => {
    isLoggingOut.current = true; // Block storage sync immediately
    hasLoadedFromStorage.current = false; // Reset loaded flag
    setIsAuthenticated(false);
    setEntities([]); // Clear local state for security
  };

  const handleImport = (importedEntities: Entity[]) => {
    // Manually override storage guard for import
    hasLoadedFromStorage.current = true;
    setEntities(importedEntities);
    storage.saveEntities(importedEntities);
  };

  if (isAuthenticated === null) {
    return (
      <div className="min-h-screen bg-slate-50 flex items-center justify-center font-mono text-[10px] text-slate-400 uppercase tracking-[0.2em] animate-pulse">
        Initializing OS...
      </div>
    );
  }

  if (!isAuthenticated) {
    return <AuthGate onAuthenticated={() => setIsAuthenticated(true)} />;
  }

  return (
    <Router>
      <Layout onLogout={handleLogout} entities={entities} onImport={handleImport}>
        <Routes>
          <Route path="/" element={<Dashboard entities={entities} />} />
          <Route path="/brain" element={<KnowledgeBrain entities={entities} onAdd={addEntity} onDelete={deleteEntity} onUpdate={updateEntity} />} />
          <Route path="/jobs" element={<JobsPipeline entities={entities} onAdd={addEntity} onDelete={deleteEntity} onUpdate={updateEntity} />} />
          <Route path="/clients" element={<ClientsTasks entities={entities} onAdd={addEntity} onDelete={deleteEntity} onUpdate={updateEntity} />} />
          <Route path="/subscriptions" element={<Subscriptions entities={entities} onAdd={addEntity} onDelete={deleteEntity} onUpdate={updateEntity} />} />
        </Routes>
      </Layout>
    </Router>
  );
};

export default App;

