const App: React.FC = () => {
  const [entities, setEntities] = useState<Entity[]>([]);
  const [isAuthenticated, setIsAuthenticated] = useState<boolean | null>(null);
  const [lastSync, setLastSync] = useState<string | null>(null);

  const isLoggingOut = useRef(false);
  const hasLoadedFromStorage = useRef(false);

  useEffect(() => {
    const checkAuth = async () => {
      const hasKey = await window.aistudio.hasSelectedApiKey();
      setIsAuthenticated(hasKey);
    };
    checkAuth();
  }, []);

  // LOAD PROCESS
  useEffect(() => {
    if (isAuthenticated === true && !hasLoadedFromStorage.current) {
      const data = storage.loadEntities();
      if (data && data.length > 0) {
        setEntities(data);
      }
      hasLoadedFromStorage.current = true;
      isLoggingOut.current = false;
      setLastSync(new Date().toLocaleTimeString());
    }
  }, [isAuthenticated]);

  // SAVE PROCESS
  useEffect(() => {
    if (isAuthenticated && !isLoggingOut.current && hasLoadedFromStorage.current) {
      storage.saveEntities(entities);
      setLastSync(new Date().toLocaleTimeString());
    }
  }, [entities, isAuthenticated]);

  const addEntity = (entity: Entity) => setEntities(prev => [entity, ...prev]);
  const deleteEntity = (id: string) => setEntities(prev => prev.filter(e => e.id !== id));
  const updateEntity = (entity: Entity) => {
    setEntities(prev => prev.map(e => e.id === entity.id ? { ...entity, updatedAt: new Date().toISOString() } : e));
  };

  const handleLogout = () => {
    isLoggingOut.current = true;
    hasLoadedFromStorage.current = false;
    setIsAuthenticated(false);
    setEntities([]);
  };

  const handleImport = (importedEntities: Entity[]) => {
    hasLoadedFromStorage.current = true;
    setEntities(importedEntities);
    storage.saveEntities(importedEntities);
    setLastSync(new Date().toLocaleTimeString());
  };

  if (isAuthenticated === null) return <div className="min-h-screen flex items-center justify-center font-mono text-[10px] uppercase tracking-widest text-slate-400">Booting ThinkStack...</div>;
  if (!isAuthenticated) return <AuthGate onAuthenticated={() => setIsAuthenticated(true)} />;

  return (
    <Router>
      <Layout onLogout={handleLogout} entities={entities} onImport={handleImport} lastSync={lastSync}>
        <Routes>
          <Route path="/" element={<Dashboard entities={entities} />} />
          <Route path="/brain" element={<KnowledgeBrain entities={entities} onAdd={addEntity} onDelete={deleteEntity} onUpdate={updateEntity} />} />
          <Route path="/jobs" element={<JobsPipeline entities={entities} onAdd={addEntity} onDelete={deleteEntity} onUpdate={updateEntity} />} />
          <Route path="/clients" element={<ClientsTasks entities={entities} onAdd={addEntity} onDelete={deleteEntity} onUpdate={updateEntity} />} />
          <Route path="/subscriptions" element={<Subscriptions entities={entities} onAdd={addEntity} onDelete={deleteEntity} onUpdate={updateEntity} />} />
        </Routes>
      </Layout>
    </Router>
  );
};

