            <div className="text-[10px] bg-green-500/20 px-2 py-1 rounded-lg font-mono text-green-400 border border-green-500/30">L-Storage OK</div>
          </div>
          <div className="space-y-6 flex-1">
             <div className="p-4 bg-slate-800/50 rounded-2xl border border-slate-700">
                <p className="text-[10px] text-slate-400 uppercase font-black tracking-widest mb-2">Local Environment</p>
                <p className="text-sm font-medium text-slate-200 leading-relaxed">
                  Your data is currently stored in your browser's private vault. It will survive computer restarts and browser updates.
                </p>
             </div>

             <div className="p-4 bg-blue-500/10 rounded-2xl border border-blue-500/30">
                <p className="text-[10px] text-blue-400 uppercase font-black tracking-widest mb-2">Backups</p>
                <p className="text-xs text-slate-300">
                  Use the <b>Export</b> button in the sidebar to download a .json file for extra safety.
                </p>
             </div>
          </div>
        </section>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
        <section>
          <div className="flex items-center justify-between mb-6 px-2">
            <h2 className="text-xs font-black uppercase tracking-[0.2em] text-slate-400">Output Pipeline</h2>
          </div>
          <div className="space-y-4">
            {urgentTasks.length > 0 ? (
              urgentTasks.map(task => <EntityCard key={task.id} entity={task} />)
            ) : (
              <div className="p-20 border-2 border-dashed border-slate-100 rounded-[2rem] text-center">
                 <p className="text-slate-300 text-sm font-medium italic">All data safe on disk. No urgent tasks.</p>
              </div>
            )}
          </div>
        </section>
      </div>
    </div>
  );
};

import React, { useRef, useState } from 'react';
import { Link, useLocation } from 'react-router-dom';
import { Entity } from '../types';

const NavItem = ({ to, icon, label, active }: { to: string, icon: string, label: string, active: boolean }) => (
  <Link 
    to={to} 
    className={`flex items-center space-x-3 px-4 py-2.5 rounded-lg transition-all duration-200 ${
      active ? 'bg-black text-white shadow-md' : 'text-slate-500 hover:bg-slate-100 hover:text-slate-900'
    }`}
  >
    <span className="text-xl">{icon}</span>
    <span className="font-medium text-sm">{label}</span>
  </Link>
);

export const Layout: React.FC<{ 
  children: React.ReactNode, 
  onLogout: () => void,
  entities: Entity[],
  onImport: (entities: Entity[]) => void,
  lastSync: string | null
}> = ({ children, onLogout, entities, onImport, lastSync }) => {
  const location = useLocation();
  const fileInputRef = useRef<HTMLInputElement>(null);
  const [showDiagnostic, setShowDiagnostic] = useState(false);

  const handleExport = () => {
    const dataStr = JSON.stringify(entities, null, 2);
    const dataUri = 'data:application/json;charset=utf-8,' + encodeURIComponent(dataStr);
    const exportFileDefaultName = `thinkstack_backup_${new Date().toISOString().split('T')[0]}.json`;
    const linkElement = document.createElement('a');
    linkElement.setAttribute('href', dataUri);
    linkElement.setAttribute('download', exportFileDefaultName);
    linkElement.click();
  };

  const handleFileChange = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (e) => {
      try {
        const json = JSON.parse(e.target?.result as string);
        if (Array.isArray(json)) onImport(json);
      } catch (err) {
        alert('Invalid backup file.');
      }
    };
    reader.readAsText(file);
  };

  return (
    <div className="flex min-h-screen bg-[#fafafa]">
      <aside className="w-64 border-r border-slate-200 bg-white p-6 flex flex-col fixed h-full shadow-[4px_0_24px_rgba(0,0,0,0.01)]">
        <div className="mb-8 px-4">
          <h1 className="text-xl font-bold tracking-tight">ThinkStack<span className="text-blue-600">.</span></h1>
          <div className="flex items-center gap-1.5 mt-1">
            <div className="w-1.5 h-1.5 bg-green-500 rounded-full animate-pulse"></div>
            <p className="text-[9px] text-green-600 font-bold uppercase tracking-widest">Disk Sync: Live</p>
          </div>
        </div>

        <nav className="space-y-1.5 flex-1">
          <NavItem to="/" icon="🏠" label="Home" active={location.pathname === '/'} />
          <NavItem to="/brain" icon="🧠" label="Knowledge" active={location.pathname === '/brain'} />
          <NavItem to="/jobs" icon="💼" label="Jobs" active={location.pathname === '/jobs'} />
          <NavItem to="/clients" icon="🤝" label="Clients & Tasks" active={location.pathname === '/clients'} />
          <NavItem to="/subscriptions" icon="💳" label="Subscriptions" active={location.pathname === '/subscriptions'} />
        </nav>

        <div className="pt-6 mt-6 border-t border-slate-100 space-y-4">
          <div className="grid grid-cols-2 gap-2">
            <button onClick={handleExport} className="flex flex-col items-center justify-center p-2 rounded-xl bg-slate-50 text-[9px] font-black text-slate-500 uppercase border border-slate-100 hover:bg-slate-100">
              <span className="text-lg mb-0.5">📤</span>Export
            </button>
            <button onClick={() => fileInputRef.current?.click()} className="flex flex-col items-center justify-center p-2 rounded-xl bg-slate-50 text-[9px] font-black text-slate-500 uppercase border border-slate-100 hover:bg-slate-100">
              <span className="text-lg mb-0.5">📥</span>Import
            </button>
            <input type="file" ref={fileInputRef} className="hidden" accept=".json" onChange={handleFileChange} />
          </div>

          <div className="p-3 bg-slate-900 rounded-xl border border-slate-800 shadow-lg">
             <div className="flex justify-between items-center mb-1">
                <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Storage Vault</p>
                <button onClick={() => setShowDiagnostic(true)} className="text-[10px] text-blue-400 hover:text-blue-300 hover:underline">Inspect</button>
             </div>
             <p className="text-xs text-white font-bold">{entities.length} Items Saved</p>
             <p className="text-[9px] text-slate-500 font-medium">Last Disk Write: {lastSync || 'Just now'}</p>
          </div>

          <button onClick={onLogout} className="w-full flex items-center justify-center space-x-2 py-2 text-slate-400 hover:text-red-500 hover:bg-red-50 rounded-lg transition-all text-xs font-bold">
             <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M17 16l4-4m0 0l-4-4m4 4H7" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/></svg>
             <span>Reset Key</span>
          </button>
        </div>
      </aside>

      <main className="flex-1 ml-64 p-8 max-w-6xl mx-auto">
        {children}
      </main>

      {showDiagnostic && (
        <div className="fixed inset-0 bg-black/40 backdrop-blur-sm z-50 flex items-center justify-center p-6">
          <div className="bg-white rounded-[2rem] p-8 max-w-2xl w-full max-h-[80vh] overflow-hidden flex flex-col shadow-2xl">
            <div className="flex justify-between items-center mb-6">
              <h2 className="text-xl font-bold">Disk Health Diagnostic</h2>
              <button onClick={() => setShowDiagnostic(false)} className="text-slate-400 hover:text-black font-black">✕</button>
            </div>
            <p className="mb-4 text-sm text-slate-600 font-medium">This is the RAW DATA currently sitting on your computer's hard drive:</p>
            <div className="flex-1 bg-slate-900 rounded-2xl p-6 overflow-auto">
              <pre className="text-green-400 font-mono text-xs leading-relaxed">
                {JSON.stringify(entities, null, 2)}
              </pre>
            </div>
            <div className="mt-4 p-4 bg-blue-50 rounded-xl border border-blue-100 flex items-center space-x-3">
               <span className="text-2xl">✅</span>
               <p className="text-xs text-blue-800 font-medium leading-relaxed">
                 ThinkStack is currently in "Local-First" mode. Your data is 100% private and 100% persistent. Closing the browser will <b>not</b> lose this information.
               </p>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};
